#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int num_iterations,
    const __global float *power,
    const __global float *temp,
    __global float *result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int block_id_x = get_group_id(0);
    int block_id_y = get_group_id(1);

    int local_id_x = get_local_id(0);
    int local_id_y = get_local_id(1);

    // The infrastructure uses an overlapping block strategy (pyramid).
    // The stride between blocks is BLOCK_SIZE - 2 * border.
    int effective_col_stride = BLOCK_SIZE - 2 * borderCols;
    int effective_row_stride = BLOCK_SIZE - 2 * borderRows;

    // Safety check for stride
    if (effective_col_stride <= 0) effective_col_stride = 1;
    if (effective_row_stride <= 0) effective_row_stride = 1;

    int c_start = block_id_x * effective_col_stride;
    int r_start = block_id_y * effective_row_stride;

    int r = r_start + local_id_y;
    int c = c_start + local_id_x;

    // Check bounds: global grid size and local block size
    if (r >= row || c >= col || local_id_x >= BLOCK_SIZE || local_id_y >= BLOCK_SIZE) {
        return;
    }

    float delta;

    // Boundary handling logic per cell
    if (r == 0 && c == 0) {
        delta = Cap_1 * (power[0] +
            (temp[1] - temp[0]) * Rx_1 +
            (temp[col] - temp[0]) * Ry_1 +
            (amb_temp - temp[0]) * Rz_1);
    } else if (r == 0 && c == col - 1) {
        delta = Cap_1 * (power[c] +
            (temp[c - 1] - temp[c]) * Rx_1 +
            (temp[c + col] - temp[c]) * Ry_1 +
            (amb_temp - temp[c]) * Rz_1);
    } else if (r == row - 1 && c == col - 1) {
        delta = Cap_1 * (power[r * col + c] +
            (temp[r * col + c - 1] - temp[r * col + c]) * Rx_1 +
            (temp[(r - 1) * col + c] - temp[r * col + c]) * Ry_1 +
            (amb_temp - temp[r * col + c]) * Rz_1);
    } else if (r == row - 1 && c == 0) {
        delta = Cap_1 * (power[r * col] +
            (temp[r * col + 1] - temp[r * col]) * Rx_1 +
            (temp[(r - 1) * col] - temp[r * col]) * Ry_1 +
            (amb_temp - temp[r * col]) * Rz_1);
    } else if (r == 0) {
        delta = Cap_1 * (power[c] +
            (temp[c + 1] + temp[c - 1] - 2.0f * temp[c]) * Rx_1 +
            (temp[col + c] - temp[c]) * Ry_1 +
            (amb_temp - temp[c]) * Rz_1);
    } else if (c == col - 1) {
        delta = Cap_1 * (power[r * col + c] +
            (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[r * col + c]) * Ry_1 +
            (temp[r * col + c - 1] - temp[r * col + c]) * Rx_1 +
            (amb_temp - temp[r * col + c]) * Rz_1);
    } else if (r == row - 1) {
        delta = Cap_1 * (power[r * col + c] +
            (temp[r * col + c + 1] + temp[r * col + c - 1] - 2.0f * temp[r * col + c]) * Rx_1 +
            (temp[(r - 1) * col + c] - temp[r * col + c]) * Ry_1 +
            (amb_temp - temp[r * col + c]) * Rz_1);
    } else if (c == 0) {
        delta = Cap_1 * (power[r * col] +
            (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0f * temp[r * col]) * Ry_1 +
            (temp[r * col + 1] - temp[r * col]) * Rx_1 +
            (amb_temp - temp[r * col]) * Rz_1);
    } else {
        // Interior cells
        delta = Cap_1 * (power[r * col + c] +
            (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[r * col + c]) * Ry_1 +
            (temp[r * col + c + 1] + temp[r * col + c - 1] - 2.0f * temp[r * col + c]) * Rx_1 +
            (amb_temp - temp[r * col + c]) * Rz_1);
    }

    result[r * col + c] = temp[r * col + c] + delta;
}
